/** CmmtMemberDao.selectList */ select
,row_number() over (order by member_nm, member_id) as rn from cmmt_member where
offset #{beginRowNum} -1 limit #{itemsPerPage}

mapper.insert:
/** CmmtMemberDao.insert */
insert into cmmt_member (
	 member_id
	,login_id
	,enc_passwd
	,passwd_dt
	,passwd_init
	,member_nm
	,nickname
	,gender
	,authority_id
	,member_st
	,member_st_dt
	,member_type
	,ci
	,enc_email
	,enc_birthday
	,enc_mobile_no
	,charger_nm
	,ceo_nm
	,bizrno
	,jurirno
	,marketing_reception
	,refresh_token
	,kakao_token
	,naver_token
	,google_token
	,creator_id
	,created_dt
	,updater_id
	,updated_dt
) values (
	 #{memberId}
	,#{loginId}
	,#{encPasswd}
	,#{passwdDt}
	,#{passwdInit}
	,#{memberNm}
	,#{nickname}
	,#{gender}
	,#{authorityId}
	,#{memberSt}
	,#{memberStDt}
	,#{memberType}
	,#{ci}
	,#{encEmail}
	,#{encBirthday}
	,#{encMobileNo}
	,#{chargerNm}
	,#{ceoNm}
	,#{bizrno}
	,#{jurirno}
	,#{marketingReception}
	,#{refreshToken}
	,#{kakaoToken}
	,#{naverToken}
	,#{googleToken}
	,#{creatorId}
	,#{createdDt}
	,#{updaterId}
	,#{updatedDt}
)

mapper.update:
/** CmmtMemberDao.update */
update cmmt_member set
	 login_id      			= #{loginId}
	,enc_passwd    			= #{encPasswd}
	,passwd_dt     			= #{passwdDt}
	,passwd_init   			= #{passwdInit}
	,member_nm     			= #{memberNm}
	,nickname      			= #{nickname}
	,gender        			= #{gender}
	,authority_id  			= #{authorityId}
	,member_st    			= #{memberSt}
	,member_st_dt  			= #{memberStDt}
	,black_list_begin_day   = #{blackListBeginDay}
	,black_list_end_day     = #{blackListEndDay}
	,black_list_reason      = #{blackListReason}
	,member_type   			= #{memberType}
	,ci            			= #{ci}
	,enc_email     			= #{encEmail}
	,enc_birthday  			= #{encBirthday}
	,enc_mobile_no 			= #{encMobileNo}
	,charger_nm				= #{chargerNm}
	,ceo_nm					= #{ceoNm}
	,bizrno        			= #{bizrno}
	,jurirno				= #{jurirno}
	,marketing_reception    = #{marketingReception}
	,refresh_token 			= #{refreshToken}
	,kakao_token            = #{kakaoToken}
	,naver_token            = #{naverToken}
	,google_token           = #{googleToken}
	,last_login_dt          = #{lastLoginDt}
	,creator_id    			= #{creatorId}
	,created_dt    			= #{createdDt}
	,updater_id    			= #{updaterId}
	,updated_dt    			= #{updatedDt}
where
	member_id = #{memberId}

mapper.select:
/** CmmtMemberDao.selectDayStatsList */
select stats_ymd as stats_day , total_mbr_cnt , join_mbr_cnt , secession_mbr_cnt , dormant_mbr_cnt , black_mbr_cnt from cmmt_member_day_stats where stats_ymd between #{beginDay} and #{endDay} and member_type = #{memberType}
select stats_ymd as stats_day , sum(total_mbr_cnt) as total_mbr_cnt , sum(join_mbr_cnt) as join_mbr_cnt , sum(secession_mbr_cnt) as secession_mbr_cnt , sum(dormant_mbr_cnt) as dormant_mbr_cnt , sum(black_mbr_cnt) as black_mbr_cnt from cmmt_member_day_stats where stats_ymd between #{beginDay} and #{endDay} group by stats_ymd
order by stats_ymd

/** CmmtMemberDao.selectMonthStatsList */
select stats_ym as stats_day , total_mbr_cnt , join_mbr_cnt , secession_mbr_cnt , dormant_mbr_cnt , black_mbr_cnt from cmmt_member_month_stats where stats_ym between substring(#{beginDay}, 1, 6) and substring(#{endDay}, 1, 6) and member_type = #{memberType}
select stats_ym as stats_day , sum(total_mbr_cnt) as total_mbr_cnt , sum(join_mbr_cnt) as join_mbr_cnt , sum(secession_mbr_cnt) as secession_mbr_cnt , sum(dormant_mbr_cnt) as dormant_mbr_cnt , sum(black_mbr_cnt) as black_mbr_cnt from cmmt_member_month_stats where stats_ym between substring(#{beginDay}, 1, 6) and substring(#{endDay}, 1, 6) group by stats_ym
order by stats_ym

